from matplotlib import pyplot as pltimport numpy as npimport cv2img = cv2.imread("../data/grains.jpg")gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)gray = np.float32(gray)plt.figure(figsize=(16,8))plt.subplot(2,2,1)plt.imshow(img)plt.title("Original Image")plt.subplot(2,2,2)plt.imshow(gray)plt.title("Gray Image")harris = cv2.cornerHarris(gray, 2, 3, 0.04)img[harris>0.01*harris.max()] = [255, 0, 0]plt.figure(figsize=(16,8))plt.subplot(2,2,1)plt.imshow(harris, cmap = 'gray')plt.title("Harris Mask Image")# =============================================================================# Shi-Tomasi Corner Detection# =============================================================================img = cv2.imread("../data/grains.jpg")gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)corners = cv2.goodFeaturesToTrack(gray, 25, 0.01, 10)for i in corners:    x, y = i.ravel()    cv2.circle(img, (int(x), int(y)), 3, 255, -1)img_rgb = cv2.cvtColor(img, cv2.COLOR_BGR2RGB)plt.subplot(2,2,2)plt.imshow(img_rgb)plt.title("Shi-Tomasi Corners Image")"""ParametersmaxCorners25Maximum number of corners to keep.qualityLevel0.01Relative corner quality threshold.Smaller value:detects more cornersmay include noiseLarger value:keeps only strong cornersminDistance10Minimum allowed distance between corners.Prevents many corners from clustering together.Corner Coordinatescorners.shapeUsually:(N,1,2)Each corner contains:[[x,y]]ravel()x, y = i.ravel()Flattens:[[x,y]]into:[x,y]Drawing Cornerscv2.circle(img, (int(x), int(y)), 3, 255, -1)Draws a filled circle at the corner location.circle Parameterscv2.circle(image, center, radius, color, thickness)center(int(x), int(y))Pixel coordinates.Must be integers.radius3Circle size.color255White color for grayscale image.For BGR image:(255,0,0)would be blue.thickness-1Filled circle."""from matplotlib import pyplot as pltimport numpy as npimport cv2img = cv2.imread("../data/grains.jpg", 0)#Oriented FAST and Rotated BRIEF#feature detector + descriptororb = cv2.ORB_create(50)#50 Maximum number of strongest keypoints to keepkp, des = orb.detectAndCompute(img, None)#Performs:#keypoint detection and descriptor computationimg2  = cv2.drawKeypoints(img, kp, None, flags = cv2.DRAW_MATCHES_FLAGS_DRAW_RICH_KEYPOINTS)plt.figure(figsize = (16,8))plt.subplot(1,2,1)plt.imshow(img2)plt.title("Key Points")"""kpkpList of keypoint objects.Each keypoint contains:positionorientationscaleresponse strengthExample:kp[0].ptreturns:(x, y)desdesDescriptor matrix.Each row corresponds to one keypoint descriptor.Used for:feature matchingsimilarity comparisondrawKeypointsimg2 = cv2.drawKeypoints(    img,    kp,    None,    flags=0)Draws detected keypoints on the image.drawKeypoints Parameterscv2.drawKeypoints(    image,    keypoints,    outImage,    flags)imageInput image.keypointsDetected keypoints list.outImageNoneOpenCV automatically creates output image.flagsControls how keypoints are visualized.flags = 0flags = 0Basic drawing mode.Draws simple circles at keypoint locations."""